BEGIN TRANSACTION;

drop schema if exists "avvocati_tribunali" cascade;

create schema "avvocati_tribunali";
set search_path to "avvocati_tribunali";

CREATE TABLE PERSONA (
    CF VARCHAR(16) PRIMARY KEY,
    Nome VARCHAR(255),
    Indirizzo VARCHAR(255),
    Citta VARCHAR(255),
    Provincia VARCHAR(50),
    CAP VARCHAR(10),
    Telefono VARCHAR(20),
    DataNascita DATE
);

CREATE TABLE AVVOCATO (
    AvvocatoID VARCHAR(50) PRIMARY KEY,
    CF VARCHAR(16) REFERENCES PERSONA(CF)
);

CREATE TABLE SPECIALIZZAZIONE (
    CodSpec VARCHAR(50) PRIMARY KEY,
    NomeSpec VARCHAR(255)
);

CREATE TABLE HA (
    AvvocatoID VARCHAR(50) REFERENCES AVVOCATO(AvvocatoID),
    CodSpec VARCHAR(50) REFERENCES SPECIALIZZAZIONE(CodSpec),
    PRIMARY KEY (AvvocatoID, CodSpec)
);

CREATE TABLE ISCRIZIONE (
    AvvocatoID VARCHAR(50) REFERENCES AVVOCATO(AvvocatoID),
    NomeAlbo VARCHAR(255),
    Data DATE,
    PRIMARY KEY (AvvocatoID, NomeAlbo)
);

CREATE TABLE TRIBUNALE (
    IdTrib VARCHAR(50) PRIMARY KEY,
    NomeTribunale VARCHAR(255),
    Citta VARCHAR(255),
    Regione VARCHAR(100),
    CAP VARCHAR(10)
);

CREATE TABLE GIUDICE (
    GiudiceID VARCHAR(50) PRIMARY KEY,
    CF VARCHAR(16) REFERENCES PERSONA(CF),
    AnniEsperienza INTEGER,
    IdTrib VARCHAR(50) REFERENCES TRIBUNALE(IdTrib)
);

CREATE TABLE CAUSA (
    IdTrib VARCHAR(50) REFERENCES TRIBUNALE(IdTrib),
    NumCausa INTEGER,
    DescrizioneCausa TEXT,
    TipoCausa VARCHAR(100),
    PRIMARY KEY (IdTrib, NumCausa)
);

CREATE TABLE UDIENZA (
    IdTrib VARCHAR(50),
    NumCausa INTEGER,
    NumUdienza INTEGER,
    Data DATE,
    Ora TIME,
    Stanza VARCHAR(50),
    GiudiceID VARCHAR(50) REFERENCES GIUDICE(GiudiceID),
    PRIMARY KEY (IdTrib, NumCausa, NumUdienza),
    FOREIGN KEY (IdTrib, NumCausa) REFERENCES CAUSA(IdTrib, NumCausa)
);

CREATE TABLE COINVOLGE (
    CF VARCHAR(16) REFERENCES PERSONA(CF),
    NumCausa INTEGER,
    IdTrib VARCHAR(50),
    RuoloP VARCHAR(100),
    PRIMARY KEY (CF, NumCausa, IdTrib),
    FOREIGN KEY (IdTrib, NumCausa) REFERENCES CAUSA(IdTrib, NumCausa)
);

CREATE TABLE RAPPRESENTA (
    AvvocatoID VARCHAR(50) REFERENCES AVVOCATO(AvvocatoID),
    CF VARCHAR(16) REFERENCES PERSONA(CF),
    NumCausa INTEGER,
    IdTrib VARCHAR(50),
    RuoloA VARCHAR(100),
    PRIMARY KEY (AvvocatoID, CF, NumCausa, IdTrib),
    FOREIGN KEY (IdTrib, NumCausa) REFERENCES CAUSA(IdTrib, NumCausa)
);

-- No INSERT statements (exam PDF source, no data instances provided)

COMMIT;

solutions:
SELECT DISTINCT CF
FROM COINVOLGE
WHERE (CF, IdTrib, NumCausa) NOT IN (
    SELECT CF, IdTrib, NumCausa
    FROM RAPPRESENTA
);

SELECT DISTINCT CF
FROM COINVOLGE LEFT OUTER NATURAL JOIN RAPPRESENTA
WHERE AvvocatoID IS NULL;

SELECT DISTINCT GiudiceID
FROM GIUDICE
WHERE (GiudiceID, IdTrib) NOT IN (
    SELECT GiudiceID, IdTrib
    FROM UDIENZA
);

SELECT DISTINCT GiudiceID
FROM GIUDICE LEFT OUTER NATURAL JOIN UDIENZA
WHERE NumCausa IS NULL;
